import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent
from azure.core.credentials import AzureKeyCredential

app = func.FunctionApp()

logging.basicConfig(level=logging.INFO)

STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL", "")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "")
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "mvpdb")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "results")
EVENTGRID_TOPIC_ENDPOINT = os.environ.get("EVENTGRID_TOPIC_ENDPOINT", "")
EVENTGRID_TOPIC_KEY = os.environ.get("EVENTGRID_TOPIC_KEY", "")
EVENTGRID_EVENT_TYPE = os.environ.get("EVENTGRID_EVENT_TYPE", "Mvp.FileProcessed")
EVENTGRID_SUBJECT_PREFIX = os.environ.get("EVENTGRID_SUBJECT_PREFIX", "files/processed")
COSMOS_PARTITION_KEY_PATH = os.environ.get("COSMOS_PARTITION_KEY_PATH", "/id")


def _credential() -> DefaultAzureCredential:
    return DefaultAzureCredential(exclude_interactive_browser_credential=True)


def _get_blob_client(container: str, blob_name: str) -> BlobClient:
    if not STORAGE_ACCOUNT_URL:
        raise ValueError("STORAGE_ACCOUNT_URL is not set")
    return BlobClient(
        account_url=STORAGE_ACCOUNT_URL,
        container_name=container,
        blob_name=blob_name,
        credential=_credential(),
    )


def _get_cosmos_container():
    if not COSMOS_ENDPOINT:
        raise ValueError("COSMOS_ENDPOINT is not set")
    client = CosmosClient(COSMOS_ENDPOINT, credential=_credential())
    db = client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
    container = db.create_container_if_not_exists(
        id=COSMOS_CONTAINER_NAME,
        partition_key=PartitionKey(path=COSMOS_PARTITION_KEY_PATH),
    )
    return container


def _get_eventgrid_client() -> EventGridPublisherClient:
    if not EVENTGRID_TOPIC_ENDPOINT:
        raise ValueError("EVENTGRID_TOPIC_ENDPOINT is not set")
    if EVENTGRID_TOPIC_KEY:
        return EventGridPublisherClient(EVENTGRID_TOPIC_ENDPOINT, AzureKeyCredential(EVENTGRID_TOPIC_KEY))
    return EventGridPublisherClient(EVENTGRID_TOPIC_ENDPOINT, _credential())


def _read_blob_text(container: str, blob_name: str) -> str:
    blob_client = _get_blob_client(container, blob_name)
    downloader = blob_client.download_blob()
    return downloader.readall().decode("utf-8", errors="replace")


def _process_content(content: str) -> Dict[str, Any]:
    lines = content.splitlines()
    non_empty_lines = [line for line in lines if line.strip()]
    word_count = sum(len(line.split()) for line in non_empty_lines)
    char_count = len(content)
    return {
        "lineCount": len(lines),
        "nonEmptyLineCount": len(non_empty_lines),
        "wordCount": word_count,
        "charCount": char_count,
    }


def _write_result_to_cosmos(document: Dict[str, Any]) -> None:
    container = _get_cosmos_container()
    container.upsert_item(document)


def _send_event(payload: Dict[str, Any]) -> None:
    client = _get_eventgrid_client()
    event = EventGridEvent(
        subject=f"{EVENTGRID_SUBJECT_PREFIX}/{payload.get('blobName', 'unknown')}",
        event_type=EVENTGRID_EVENT_TYPE,
        data_version="1.0",
        data=payload,
    )
    client.send([event])


@app.function_name(name="ProcessBlobFile")
@app.blob_trigger(arg_name="blob", path="%INPUT_CONTAINER%/{name}", connection="AzureWebJobsStorage")
def process_blob_file(blob: func.InputStream) -> None:
    try:
        container_name = os.environ.get("INPUT_CONTAINER", "")
        blob_name = blob.name.split("/", 1)[-1] if "/" in blob.name else blob.name
        content = blob.read().decode("utf-8", errors="replace")
        result = _process_content(content)

        document = {
            "id": f"{container_name}:{blob_name}",
            "partitionKey": f"{container_name}",
            "container": container_name,
            "blobName": blob_name,
            "processedAt": datetime.now(timezone.utc).isoformat(),
            "metrics": result,
            "sourceLength": len(content),
        }

        _write_result_to_cosmos(document)

        event_payload = {
            "status": "Processed",
            "container": container_name,
            "blobName": blob_name,
            "documentId": document["id"],
            "metrics": result,
            "processedAt": document["processedAt"],
        }
        _send_event(event_payload)

        logging.info("Processed blob %s/%s", container_name, blob_name)
    except Exception as exc:
        logging.exception("Failed to process blob: %s", exc)
        raise


